def second_largest(nums):
    """
    Matches the requested format.
    Handles duplicates and returns None if there is no second distinct value.
    """
    if len(set(nums)) < 2:
        return None
    else:
        unique_nums = sorted(list(set(nums)), reverse=True)
        for i in range(len(unique_nums) - 1):
            if unique_nums[i] != unique_nums[i + 1]:
                return unique_nums[i]
        return None
